export function nextGeneration(cells: Cell[]): Cell[] {
  const isAlive = (x: number, y: number): boolean =>
    cells.some(([cx, cy]) => cx === x && cy === y);
  const countNeighbors = (x: number, y: number): number =>
    NEIGHBOR_OFFSETS.filter(([dx, dy]) => isAlive(x + dx, y + dy)).length;
  const key = ([x, y]: Cell): string => `${x},${y}`;
  const candidates = new Map<string, Cell>();
  const addCandidate = (c: Cell): void => {
    candidates.set(key(c), c);
  };
  for (const [x, y] of cells) {
    addCandidate([x, y]);
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      addCandidate([x + dx, y + dy]);
    }
  }
  return [...candidates.values()].filter(([x, y]) => {
    const n = countNeighbors(x, y);
    return isAlive(x, y)
      ? SURVIVAL_NEIGHBOR_COUNTS.includes(n)
      : n === REPRODUCTION_NEIGHBORS;
  });
}

