export function nextGeneration(cells: Cell[]): Cell[] {
  const liveCells = new Set(cells.map(cellKey));
  const isAlive = (cell: Cell): boolean => liveCells.has(cellKey(cell));
  const countLiveNeighbors = (cell: Cell): number =>
    neighborsOf(cell).filter(isAlive).length;
  const survivesOrIsBorn = (cell: Cell): boolean => {
    const liveNeighbors = countLiveNeighbors(cell);
    return isAlive(cell)
      ? SURVIVAL_NEIGHBOR_COUNTS.includes(liveNeighbors)
      : liveNeighbors === REPRODUCTION_NEIGHBORS;
  };
  return candidateCells(cells).filter(survivesOrIsBorn);
}

function cellKey([x, y]: Cell): string {
  return `${x},${y}`;
}

function neighborsOf([x, y]: Cell): Cell[] {
  return NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
}

function candidateCells(liveCells: Cell[]): Cell[] {
  const candidates = new Map<string, Cell>();
  for (const cell of liveCells) {
    candidates.set(cellKey(cell), cell);
    for (const neighbor of neighborsOf(cell)) {
      candidates.set(cellKey(neighbor), neighbor);
    }
  }
  return [...candidates.values()];
}
